fn main() {
    let nums = vec![1, 2, 3, 4, 5];
    let doubled: Vec<i32> = nums.iter().map(|n| n * 2).collect();
    for d in &doubled {
        println!("{}", d);
    }
}

fn main() {
    let nums = vec![1, 2, 3, 4, 5];
    let evens: Vec<i32> = nums.iter().filter(|n| *n % 2 == 0).copied().collect();
    for e in &evens {
        println!("{}", e);
    }
}

